// ─────────────────────────────────────────────────────────────────
// Error states
// ─────────────────────────────────────────────────────────────────
test.describe('Sutter Import Visual — Error States', () => {
  test('no valid tabs shows error', async ({ page }) => {
    const importPage = new ImportPage(page);
    try {
      await importPage.goto(ADMIN_KO.email, ADMIN_KO.password);
    } catch {
      await importPage.goto(ADMIN.email, ADMIN.password);
    }

    const fixturePath = await getNoValidTabsFixturePath();
    await importPage.selectSystem('sutter');
    await importPage.uploadFile(fixturePath);
    await importPage.waitForSheetDiscovery();

    const errorText = await importPage.getSheetErrorText();
    const anyErrorVisible = errorText.length > 0 ||
      await page.locator('text=/[Nn]o.*physician.*tab|[Nn]o valid tab/').isVisible().catch(() => false);
    expect(anyErrorVisible).toBe(true);
    await page.screenshot({ path: 'test-results/sutter-visual-15-no-valid-tabs.png' });
  });

  test('empty tab shows error on preview', async ({ page }) => {
    const importPage = new ImportPage(page);
    try {
      await importPage.goto(ADMIN_KO.email, ADMIN_KO.password);
    } catch {
      await importPage.goto(ADMIN.email, ADMIN.password);
    }

    const fixturePath = await getEmptyTabFixturePath();
    await importPage.selectSystem('sutter');
    await importPage.uploadFile(fixturePath);
    await importPage.waitForSheetDiscovery();

    const selectedSheet = await importPage.getSelectedSheet();
    if (!selectedSheet) {
      await importPage.selectSheet('Empty, Doctor');
    }

    await importPage.physicianDropdown.waitFor({ state: 'visible', timeout: 5000 });
    await selectFirstPhysician(importPage);
    await importPage.clickPreview();

    // Wait for error response — either an error appears on import page or we navigate to preview with an error
    await Promise.race([
      page.locator('.bg-red-50').first().waitFor({ state: 'visible', timeout: 15000 }),
      page.waitForURL(/\/preview\//, { timeout: 15000 }),
    ]).catch(() => {});
    await page.screenshot({ path: 'test-results/sutter-visual-16-empty-tab-error.png' });
  });

  test('missing physician shows warning', async ({ page }) => {
    const importPage = new ImportPage(page);
    try {
      await importPage.goto(ADMIN_KO.email, ADMIN_KO.password);
    } catch {
      await importPage.goto(ADMIN.email, ADMIN.password);
    }

    const fixturePath = await getMultiTabFixturePath();
    await setupSutterUpload(importPage, fixturePath);

    await importPage.selectSheet('Smith, John');
    await importPage.physicianDropdown.waitFor({ state: 'visible', timeout: 5000 });
    await importPage.physicianDropdown.selectOption('');

    const warningVisible = await importPage.isPhysicianWarningVisible();
    expect(warningVisible).toBe(true);
    await page.screenshot({ path: 'test-results/sutter-visual-17-missing-physician.png' });
  });
});
